INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-01224', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '針對接受過穿透性角膜移植手術（penetratingkeratoplasty,PKP）的病人，何者並非使用隱形眼鏡的適應症？', '["角膜上皮癒合不良或傷口滲漏", "術後之不規則散光", "術後之雙眼視差", "術後造成的高眼壓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01225', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關使用化學消毒法，來消毒軟式隱形眼鏡的方法，下列何者錯誤？', '["化學消毒法又可稱為多功能（三合一）系統， 集洗、沖、消毒於一瓶藥水。優點是簡單，缺點是在消毒 過程中，藥水中的防腐劑化學成分會滲入鏡片中", "目前使用在化學消毒法中的新型防腐劑化學成分比起早期的硫柳汞（thimerosal），較不會引起過敏反應 的原因是其較小的分子量，也比較容易被代謝掉", "美國曾經爆發的棘狀阿米巴原蟲角膜感染，被認為與美國的自來水化學物成分改變或淨水方式改變有 關，令棘狀阿米巴原蟲量增加", "若要以化學消毒法有效去除鏡片上的棘狀阿米巴原蟲，使用清潔液，並且在沖洗鏡片前先用手指搓洗是 一個最重要的步驟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01226', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關使用雙氧水消毒法，消毒軟式隱形眼鏡的方法，下列何者錯誤？', '["把清潔及沖洗後的鏡片置於雙氧水中消毒。在雙氧水中浸泡的時間越久，其抑制黴菌、棘狀阿米巴原蟲 的效果就越強大", "所使用的 3%過氧化氫帶有弱鹼性，是會刺激或損害眼睛的，所以鏡片於雙氧水消毒後，必須經過一個 中和程序才可使用", "中和方法有很多種，包括把鏡片從雙氧水中拿出，再置於中和藥水內。也可以在把鏡片置於雙氧水中的 同時，放入一粒中和藥丸或一個中和金屬環", "雙氧水消毒所需時間及中和所需時間，從數十分鐘到數小時不等。優點是如果雙氧水不含防腐劑且完全 中和，是不會引起眼睛敏感的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01227', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '病患屈光矯正的散光軸在 170 度，使用記號標記在 0 和 180 度的隱形眼鏡試片，戴上試片後記號顯示在 165度，則處方鏡片之角度應為何？', '["5度", "95度", "165度", "170度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01228', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者眼角膜參數為 HVID＝11.5 mm、角膜 K 值 7.95 mm@170/7.85 mm@080，驗光處方屈光度 （power）＝-3.00D，給患者試戴未知基弧（BC）的硬式透氣隱形眼鏡（RGP），試片已知其餘參數為直徑 （OAD）＝9.40mm、屈光度＝-3.00D，戴鏡驗光（over-refraction）檢查須再加+1.00DS才可看清視力表 20/20的視力，則試片的基弧最接近下列何者？', '["8.15mm", "7.95mm", "7.75mm", "8.20mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01229', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者配戴的硬式透氣隱形眼鏡（RGP）參數為基弧（BC）＝7.95mm、直徑（OAD）＝9.60mm、屈光 度（power）＝-4.00D，產生+1.25D淚液鏡（tearlens）效應，求患者角膜平K（flatk）值最接近下列何者？', '["7.83mm", "7.72mm", "8.07mm", "8.19mm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01230', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列那一種因素會導致原本「合適的配適」（well-fitting）軟式隱形眼鏡片，在複檢（followup）時會看起 來像「鬆配適」（loosesoftlensfit）鏡片？', '["乾眼患者配戴長時間後", "長途飛行後", "配戴隱形眼鏡睡覺後", "鏡片戴反"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01231', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴某試片後，滑動及中心定位都理想，基弧9.0mm，直徑14.2mm，屈光度-4.00DS，戴鏡驗光（over- refraction）屈光度為+8.00DS、配戴者視力可達1.0、插片頂點距離＝13mm、隱形眼鏡處方度數為：', '["-11.25DS", "-12.00DS", "+12.75DS", "+4.75DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01232', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜弧度測量法（keratometry）的敘述，下列何者錯誤？', '["可測量角膜曲率半徑，以作為選擇隱形眼鏡基弧的參考", "一般的角膜弧度測量儀是測量距離角膜中心點兩側各3mm的地方", "主要測量角膜前表面的弧度", "從角膜鏡面反射（mire）的形狀，可判斷角膜表面是否規則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01233', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者之屈光度為-3.50DS，角膜弧度為7.85mm，若使用基弧7.7mm的硬式隱形眼鏡矯正，則隱形眼鏡之 屈光度應為何？', '["-2.75DS", "-3.25DS", "-3.75DS", "-4.25DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
